#include <bits/stdc++.h>
using namespace std;
int b[14];
int main(){
    int n;
    string a;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>a;
        int c=0,f=0;
        for(int j=a.length()-1;j>=0;j--){
            c++;
            b[j]=a[j]-'0';
            if(c%2==1){
                b[j]*=7;
                while(b[j]>9){
                    int d=0;
                    while(b[j]!=0){
                        d+=b[j]%10;
                        b[j]=b[j]/10;
                    }
                    b[j]=d;
                }
            }
            f+=b[j];
        }
        f=f%8;
        if(f!=0){
            cout<<"F";
        }
        else{
            cout<<"T";
        }
        cout<<endl;
    }
    return 0;
}
